Here's a modern MSTest 3.x test class for `DataFetcher`:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    private readonly TestContext _testContext;

    public DataFetcherTests(TestContext testContext)
    {
        _testContext = testContext;
    }

    private static DataFetcher CreateFetcher(HttpMessageHandler handler)
        => new(new HttpClient(handler));

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_SuccessResponse_ReturnsContent()
    {
        // Arrange
        var handler = new FakeHandler(new HttpResponseMessage(HttpStatusCode.OK)
        {
            Content = new StringContent("hello")
        });
        var fetcher = CreateFetcher(handler);

        // Act
        var result = await fetcher.FetchAsync("https://example.com",
            _testContext.CancellationToken);

        // Assert
        Assert.AreEqual("hello", result);
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_NotFound_ThrowsHttpRequestException()
    {
        var handler = new FakeHandler(
            new HttpResponseMessage(HttpStatusCode.NotFound));
        var fetcher = CreateFetcher(handler);

        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            async () => await fetcher.FetchAsync("https://example.com/missing",
                _testContext.CancellationToken));
    }

    [TestMethod]
    [Timeout(3000)]
    public async Task FetchAsync_CancellationRequested_ThrowsTaskCanceledException()
    {
        // Handler that delays forever â€” cancellation should interrupt it
        var handler = new FakeHandler(async (_, ct) =>
        {
            await Task.Delay(Timeout.Infinite, ct);
            return new HttpResponseMessage(); // unreachable
        });
        var fetcher = CreateFetcher(handler);
        using var cts = new CancellationTokenSource();
        cts.Cancel(); // cancel immediately

        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync("https://example.com", cts.Token));
    }

    [TestMethod]
    [Timeout(3000)]
    public async Task FetchAsync_TimeoutExpires_Throws()
    {
        // Simulate a slow server
        var handler = new FakeHandler(async (_, ct) =>
        {
            await Task.Delay(TimeSpan.FromSeconds(10), ct);
            return new HttpResponseMessage();
        });
        var fetcher = CreateFetcher(handler);
        using var cts = new CancellationTokenSource(TimeSpan.FromMilliseconds(50));

        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync("https://example.com", cts.Token));
    }

    // Lightweight fake â€” no mocking library needed
    private sealed class FakeHandler : HttpMessageHandler
    {
        private readonly Func<HttpRequestMessage, CancellationToken,
            Task<HttpResponseMessage>> _send;

        public FakeHandler(HttpResponseMessage canned)
            : this((_, _) => Task.FromResult(canned)) { }

        public FakeHandler(
            Func<HttpRequestMessage, CancellationToken,
                Task<HttpResponseMessage>> send)
            => _send = send;

        protected override Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
            => _send(request, cancellationToken);
    }
}
```

**Key patterns used:**

| Pattern | Why |
|---|---|
| `sealed` class | Performance & design clarity |
| `TestContext` via constructor | Enables `readonly`, satisfies nullability |
| `_testContext.CancellationToken` | Cooperative timeout â€” `[Timeout]` auto-cancels this token |
| `Assert.ThrowsExactlyAsync<T>` | Modern replacement for `[ExpectedException]`, exact type match |
| `FakeHandler` | Controls `HttpClient` behavior without a mocking library |

The critical detail: **always pass `TestContext.CancellationToken`** (or a derived `CancellationTokenSource`) to async calls. The `[Timeout]` attribute fires that token when time expires, ensuring tests don't hang indefinitely.
